patch:
diff --git a/llvm/lib/Analysis/InstructionSimplify.cpp b/llvm/lib/Analysis/InstructionSimplify.cpp
index 7bff13d59528..07ec8357eada 100644
--- a/llvm/lib/Analysis/InstructionSimplify.cpp
+++ b/llvm/lib/Analysis/InstructionSimplify.cpp
@@ -1850,6 +1850,56 @@ static Value *simplifyAndOrOfFCmps(const SimplifyQuery &Q, FCmpInst *LHS,
                  : ConstantInt::getBool(LHS->getType(), !IsAnd);
   }

+
+  // For (fcmp pred X, C1) and/or (fcmp pred X, C2):
+  //   For less-than predicates (olt/ole/ult/ule):
+  //     OR:  take max(C1, C2) → weaker condition
+  //     AND: take min(C1, C2) → stricter condition
+  //   For greater-than predicates (ogt/oge/ugt/uge):
+  //     OR:  take min(C1, C2) → weaker condition
+  //     AND: take max(C1, C2) → stricter condition
+  if (PredL == PredR && LHS0 == RHS0) {
+    const APFloat *C1, *C2;
+    if (match(LHS1, m_APFloatAllowPoison(C1)) &&
+        match(RHS1, m_APFloatAllowPoison(C2))) {
+      auto IsLessThan = [](FCmpInst::Predicate Pred) {
+        switch (Pred) {
+        case FCmpInst::FCMP_OLT:
+        case FCmpInst::FCMP_OLE:
+        case FCmpInst::FCMP_ULT:
+        case FCmpInst::FCMP_ULE:
+          return true;
+        default:
+          return false;
+        }
+      };
+      auto IsGreaterThan = [](FCmpInst::Predicate Pred) {
+        switch (Pred) {
+        case FCmpInst::FCMP_OGT:
+        case FCmpInst::FCMP_OGE:
+        case FCmpInst::FCMP_UGT:
+        case FCmpInst::FCMP_UGE:
+          return true;
+        default:
+          return false;
+        }
+      };
+      if (IsLessThan(PredL) || IsGreaterThan(PredL)) {
+        bool LHSTaken;
+        if (IsLessThan(PredL)) {
+          // For less-than: larger constant = weaker condition.
+          // OR takes max, AND takes min.
+          LHSTaken = IsAnd ? (*C1 < *C2) : (*C1 > *C2);
+        } else {
+          // For greater-than: smaller constant = weaker condition.
+          // OR takes min, AND takes max.
+          LHSTaken = IsAnd ? (*C1 > *C2) : (*C1 < *C2);
+        }
+        return static_cast<Value *>(LHSTaken ? LHS : RHS);
+      }
+    }
+  }
+
   return nullptr;
 }

